import React from 'react';
import { Card, CardContent, Box, Typography, Grid } from '@mui/material';
import response from './response.json';

interface WidgetData {
  variables: string[];
  correlationMatrix: number[][];
  heatmapColors: string[][];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const { variables, correlationMatrix, heatmapColors } = widgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 400, maxWidth: 600, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Typography variant="h6" fontWeight={700} sx={{ mb: 2, color: '#000000' }}>
          Correlation Matrix
        </Typography>
        <Grid container spacing={0.5}>
          {variables.map((variable, index) => (
            <Grid item xs={3} key={index}>
              <Typography variant="body2" sx={{ color: '#000000', textAlign: 'center', fontWeight: 600 }}>
                {variable}
              </Typography>
            </Grid>
          ))}
          {correlationMatrix.map((row, rowIndex) =>
            row.map((value, colIndex) => (
              <Grid item xs={3} key={`${rowIndex}-${colIndex}`}>
                <Box
                  sx={{
                    bgcolor: heatmapColors[rowIndex][colIndex],
                    height: 40,
                    display: 'flex',
                    justifyContent: 'center',
                    alignItems: 'center',
                    border: '1px solid #e0e0e0',
                  }}
                >
                  <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                    {value.toFixed(1)}
                  </Typography>
                </Box>
              </Grid>
            ))
          )}
        </Grid>
      </CardContent>
    </Card>
  );
}
